import{_ as a,o as t,c as i,a2 as s}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"Chapter 12: Permission and Safety","description":"Comprehensive safety architecture for coding agents, covering threat models, permission systems, sandboxing, and audit trails.","frontmatter":{"title":"Chapter 12: Permission and Safety","description":"Comprehensive safety architecture for coding agents, covering threat models, permission systems, sandboxing, and audit trails."},"headers":[],"relativePath":"learn/project/12-permission-and-safety/index.md","filePath":"learn/project/12-permission-and-safety/index.md"}'),n={name:"learn/project/12-permission-and-safety/index.md"};function r(o,e,l,d,c,p){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="permission-and-safety" tabindex="-1">Permission and Safety <a class="header-anchor" href="#permission-and-safety" aria-label="Permalink to &quot;Permission and Safety&quot;">​</a></h1><p>A coding agent that can read files, execute shell commands, and modify a codebase is inherently powerful and inherently dangerous. This chapter builds the safety infrastructure that makes that power trustworthy. You will design and implement a layered defense system that prevents the agent from performing harmful operations while keeping it productive for legitimate tasks.</p><p>The chapter begins with threat modeling specific to coding agents — understanding what can go wrong when an LLM has access to a filesystem and a shell. From there, you will implement permission levels that categorize operations by risk, an approval system that gates dangerous actions on human confirmation, and file checkpoints that enable reliable undo. You will also build allowlists and denylists for command filtering, a plan mode for previewing changes before execution, dangerous operation detection heuristics, and sandboxing to contain agent operations within safe boundaries. The chapter concludes with audit logging for accountability and strategies for testing that your safety systems actually work.</p><p>Safety is not a single feature but a philosophy that permeates the entire agent. By the end of this chapter, your agent will have defense in depth: multiple independent safety layers that each catch different categories of risk, ensuring that no single failure can lead to catastrophic outcomes.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Design a threat model specific to LLM-powered coding agents</li><li>Implement a tiered permission system that categorizes operations by risk level</li><li>Build an approval workflow that pauses for human confirmation on dangerous actions</li><li>Create file checkpoints and undo capabilities for reliable rollback</li><li>Construct allowlists and denylists for filtering shell commands and file paths</li><li>Implement plan mode for previewing changes before execution</li><li>Detect dangerous operations through pattern matching and heuristic scoring</li><li>Apply sandboxing techniques to constrain filesystem and network access</li><li>Record structured audit logs for debugging and post-incident analysis</li><li>Test safety systems with red-team scenarios and property-based testing</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/project/12-permission-and-safety/01-threat-model.html">Threat Model</a></li><li><a href="/project/12-permission-and-safety/02-permission-levels.html">Permission Levels</a></li><li><a href="/project/12-permission-and-safety/03-approval-system.html">Approval System</a></li><li><a href="/project/12-permission-and-safety/04-file-checkpoints.html">File Checkpoints</a></li><li><a href="/project/12-permission-and-safety/05-undo-revert.html">Undo and Revert</a></li><li><a href="/project/12-permission-and-safety/06-allowlists-denylists.html">Allowlists and Denylists</a></li><li><a href="/project/12-permission-and-safety/07-plan-mode.html">Plan Mode</a></li><li><a href="/project/12-permission-and-safety/08-dangerous-operation-detection.html">Dangerous Operation Detection</a></li><li><a href="/project/12-permission-and-safety/09-sandboxing-deep-dive.html">Sandboxing Deep Dive</a></li><li><a href="/project/12-permission-and-safety/10-audit-logging.html">Audit Logging</a></li><li><a href="/project/12-permission-and-safety/11-testing-safety.html">Testing Safety</a></li><li><a href="/project/12-permission-and-safety/12-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 6: Shell execution with process spawning, timeouts, and basic command filtering</li><li>Chapter 11: Git integration for repository operations, checkpointing, and safe rollback</li><li>Familiarity with Rust enums, traits, and the <code>Result</code> type</li></ul>',10)])])}const f=a(n,[["render",r]]);export{m as __pageData,f as default};
